import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Shared Database Change","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/playbooks/shared-database-change.md","filePath":"projects/arti/playbooks/shared-database-change.md"}'),t={name:"projects/arti/playbooks/shared-database-change.md"};function n(s,a,o,h,d,c){return i(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="shared-database-change" tabindex="-1">Shared Database Change <a class="header-anchor" href="#shared-database-change" aria-label="Permalink to &quot;Shared Database Change&quot;">​</a></h1><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>修改多个仓库共同使用的：</p><ul><li>Table 或 Column</li><li>RLS Policy</li><li>RPC / Function</li><li>Trigger</li><li>Enum 字符串约束</li><li>Realtime Publication</li></ul><h2 id="红线" tabindex="-1">红线 <a class="header-anchor" href="#红线" aria-label="Permalink to &quot;红线&quot;">​</a></h2><ul><li>已应用 migration 不回改。</li><li>非 Owner 仓库不发布共享对象 DDL。</li><li>不从另一仓库复制旧函数后整体覆盖。</li><li>不把文档里的 SQL 示例直接当生产 migration。</li><li>不在未核对生产定义时执行 <code>CREATE OR REPLACE FUNCTION</code>。</li></ul><h2 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h2><h3 id="_1-确认-owner" tabindex="-1">1. 确认 Owner <a class="header-anchor" href="#_1-确认-owner" aria-label="Permalink to &quot;1. 确认 Owner&quot;">​</a></h3><p>从 <a href="./../source-of-truth.html">项目真源</a> 查 Owner。没有 Owner 时，先做项目决策，不直接写 migration。</p><h3 id="_2-读取三份事实" tabindex="-1">2. 读取三份事实 <a class="header-anchor" href="#_2-读取三份事实" aria-label="Permalink to &quot;2. 读取三份事实&quot;">​</a></h3><p>必须同时查看：</p><ol><li>Owner 仓库最新 migration</li><li>其他仓库对该对象的调用或历史 DDL</li><li>生产当前 Schema 或函数定义</li></ol><p>文件存在不代表 migration 已在生产应用。</p><h3 id="_3-列出不变量" tabindex="-1">3. 列出不变量 <a class="header-anchor" href="#_3-列出不变量" aria-label="Permalink to &quot;3. 列出不变量&quot;">​</a></h3><p>示例：</p><ul><li><code>dedupe_key</code> 仍为非空并保持唯一</li><li><code>settle_market</code> 仍写通知</li><li>Credits 锁顺序不变</li><li><code>report_tasks</code> 状态集合不变</li></ul><h3 id="_4-设计向前迁移" tabindex="-1">4. 设计向前迁移 <a class="header-anchor" href="#_4-设计向前迁移" aria-label="Permalink to &quot;4. 设计向前迁移&quot;">​</a></h3><ul><li>新建递增时间戳 migration</li><li>使用明确的前置检查</li><li>保留历史数据读兼容</li><li>需要回填时单独设计可重跑脚本</li></ul><h3 id="_5-检查所有消费者" tabindex="-1">5. 检查所有消费者 <a class="header-anchor" href="#_5-检查所有消费者" aria-label="Permalink to &quot;5. 检查所有消费者&quot;">​</a></h3><p>搜索所有仓库中的：</p><ul><li>Table 名</li><li>RPC 名</li><li>字段名</li><li>Type 字符串</li><li>Response shape</li></ul><h3 id="_6-验证" tabindex="-1">6. 验证 <a class="header-anchor" href="#_6-验证" aria-label="Permalink to &quot;6. 验证&quot;">​</a></h3><ul><li>在 Branch、Staging 或等价环境应用</li><li>跑正常业务路径</li><li>跑重复请求和失败重试</li><li>跑越权与对抗性调用</li><li>验证余额、流水、通知和任务副作用</li></ul><h3 id="_7-发布" tabindex="-1">7. 发布 <a class="header-anchor" href="#_7-发布" aria-label="Permalink to &quot;7. 发布&quot;">​</a></h3><p>默认顺序：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>向后兼容 DB migration</span></span>
<span class="line"><span>  → Server writers</span></span>
<span class="line"><span>  → Readers / UI</span></span>
<span class="line"><span>  → Backfill</span></span>
<span class="line"><span>  → 删除旧兼容</span></span></code></pre></div><h3 id="_8-记录" tabindex="-1">8. 记录 <a class="header-anchor" href="#_8-记录" aria-label="Permalink to &quot;8. 记录&quot;">​</a></h3><ul><li>在 migration 注释写明 Owner 和 RFC</li><li>更新跨仓契约</li><li>在姊妹 RFC 回填生产验证</li></ul><h2 id="事故触发条件" tabindex="-1">事故触发条件 <a class="header-anchor" href="#事故触发条件" aria-label="Permalink to &quot;事故触发条件&quot;">​</a></h2><p>出现以下任一情况，停止继续发布并进入事故处理：</p><ul><li>余额或结算结果不一致</li><li>权限范围扩大</li><li>通知或退款副作用丢失</li><li>新旧客户端无法同时工作</li><li>生产函数与预期 migration 不一致</li></ul>`,31)])])}const b=e(t,[["render",n]]);export{u as __pageData,b as default};
